const input = $input.first().json;
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

const resourceId = payload.resourceId || '';

return {
  json: {
    event_id: eventId,
    project_id: projectId || null,
    lexware_voucher_id: resourceId,
    step_key: `lexware_voucher_status:${resourceId}`
  }
};

const resp = $input.first().json;
const v = resp.body || resp;
const eventData = $('Parse Event Data').first().json;

const voucherStatus = (v.voucherStatus || '').toLowerCase();
const paidAmount = parseFloat(v.paidAmount || 0);
const openAmount = parseFloat(v.openAmount || 0);
const totalGross = parseFloat(v.totalGrossAmount || 0);
const dueDate = v.dueDate ? v.dueDate.substring(0, 10) : null;

// Map Lexware status to BG sync_status
let syncStatus = 'synced';
if (voucherStatus === 'paid' || voucherStatus === 'paidoff') syncStatus = 'paid';
else if (voucherStatus === 'overdue') syncStatus = 'overdue';
else if (voucherStatus === 'voided') syncStatus = 'voided';

return {
  json: {
    lexware_voucher_id: eventData.lexware_voucher_id,
    voucher_status: voucherStatus,
    paid_amount: paidAmount,
    open_amount: openAmount,
    total_gross: totalGross,
    due_date: dueDate,
    sync_status: syncStatus
  }
};

